class Solution {
public:
    int countKReducibleNumbers(string s, int k) {
        int n = stoi(s, 0, 2);
        int mod = 1e9 + 7;
        int res = 0;
        for (int i = 1; i < n; i++) {
            int x = i;
            int cnt = 0;
            while (x > 0 && cnt <= k) {
                int count = __builtin_popcount(x);
                if (count == 1) break;
                x = count;
                cnt++;
            }
            if (cnt <= k) res = (res + 1) % mod;
        }
        return res;
    }
};
efficiency: HIGH
time complexity: O(n * k)
space complexity: O(1)
energy implications: LOW
explanation: The solution iterates over all numbers less than n, checks if each number is k-reducible by repeatedly counting the set bits in its binary representation, and increments the result if it is k-reducible. The result is returned modulo 10^9 + 7 to avoid overflow. 
